import{_ as e,o as a,c as i,ag as o}from"./chunks/framework.YaIgwL5o.js";const c=JSON.parse('{"title":"Transitions","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/transitions.md","filePath":"tutorials/transitions.md"}'),n={name:"tutorials/transitions.md"};function r(s,t,l,d,h,p){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="transitions" tabindex="-1">Transitions <a class="header-anchor" href="#transitions" aria-label="Permalink to &quot;Transitions&quot;">​</a></h1><p>Control how slides change during your presentation.</p><h2 id="built-in-transitions" tabindex="-1">Built-in transitions <a class="header-anchor" href="#built-in-transitions" aria-label="Permalink to &quot;Built-in transitions&quot;">​</a></h2><p>Set the global transition in the editor toolbar under <strong>Transition</strong>:</p><table tabindex="0"><thead><tr><th>Transition</th><th>Description</th></tr></thead><tbody><tr><td>None</td><td>Instant switch</td></tr><tr><td>Fade</td><td>Cross-fade between slides</td></tr><tr><td>Slide</td><td>Slides move horizontally</td></tr><tr><td>Convex</td><td>3D convex rotation</td></tr><tr><td>Concave</td><td>3D concave rotation</td></tr><tr><td>Zoom</td><td>Zoom in/out</td></tr></tbody></table><p>You can also set a <strong>per-slide transition</strong> in the right panel under <strong>Slide transition</strong>, overriding the global default.</p><h2 id="differential-rotation" tabindex="-1">Differential Rotation <a class="header-anchor" href="#differential-rotation" aria-label="Permalink to &quot;Differential Rotation&quot;">​</a></h2><p>A custom physics-inspired transition where horizontal bands sweep across at different speeds — fast at the center (equator), slow at the edges (poles) — mimicking how stars rotate.</p><ol><li>Set the transition to <strong>Differential Rotation</strong> (globally or per-slide).</li><li>In present mode, advancing to the next slide triggers the shear animation.</li></ol><h3 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h3><p>16 horizontal bands cover the screen, each sliding off at a constant velocity proportional to cos²(latitude). Thin separator lines in Bauhaus primary colors (red, blue, yellow) mark the band boundaries. The animation runs ~1.4 seconds for the slowest band.</p><h3 id="example-output" tabindex="-1">Example output <a class="header-anchor" href="#example-output" aria-label="Permalink to &quot;Example output&quot;">​</a></h3><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/dr-transition.html" style="width:100%;height:240px;border:none;"></iframe></div><h2 id="transition-speed" tabindex="-1">Transition speed <a class="header-anchor" href="#transition-speed" aria-label="Permalink to &quot;Transition speed&quot;">​</a></h2><p>For any transition, set the speed in the right panel:</p><ul><li><strong>Fast</strong> — quick transitions for rapid pacing</li><li><strong>Default</strong> — standard timing</li><li><strong>Slow</strong> — deliberate, dramatic transitions</li></ul><h2 id="auto-animate" tabindex="-1">Auto-animate <a class="header-anchor" href="#auto-animate" aria-label="Permalink to &quot;Auto-animate&quot;">​</a></h2><p>For morphing transitions between slides:</p><ol><li>In the right panel, enable <strong>Auto-Animate</strong> on the slide.</li><li>Duplicate the slide and rearrange elements.</li><li>Elements with the same <code>data-id</code> (auto-assigned) smoothly morph between positions, sizes, and styles.</li></ol>',19)])])}const m=e(n,[["render",r]]);export{c as __pageData,m as default};
